// ---- Basic state ----
@Composable
fun Counter() {
    // State variable
    var count by remember { mutableStateOf(0) }

    Column(
        modifier = Modifier.padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = "Count: $count",
            fontSize = 24.sp
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = { count-- }) {
                Text("-")
            }
            Button(onClick = { count++ }) {
                Text("+")
            }
            Button(onClick = { count = 0 }) {
                Text("Reset")
            }
        }
    }
}

// ---- State with multiple variables ----
@Composable
fun UserProfile() {
    var name by remember { mutableStateOf("Kotlin-chan") }
    var age by remember { mutableStateOf(25) }
    var isEditing by remember { mutableStateOf(false) }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        if (isEditing) {
            // Edit mode
            OutlinedTextField(
                value = name,
                onValueChange = { name = it },
                label = { Text("Name") }
            )
            OutlinedTextField(
                value = age.toString(),
                onValueChange = { age = it.toIntOrNull() ?: age },
                label = { Text("Age") }
            )
            Button(onClick = { isEditing = false }) {
                Text("Save")
            }
        } else {
            // View mode
            Text(text = "Name: $name", fontSize = 18.sp)
            Text(text = "Age: $age", fontSize = 18.sp)
            Button(onClick = { isEditing = true }) {
                Text("Edit")
            }
        }
    }
}

// ---- State with objects ----
data class UserState(
    val name: String = "",
    val age: Int = 0,
    val isLoggedIn: Boolean = false
)

@Composable
fun UserStateExample() {
    var userState by remember { mutableStateOf(UserState()) }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text(text = "Name: ${userState.name}")
        Text(text = "Age: ${userState.age}")
        Text(text = "Logged in: ${userState.isLoggedIn}")

        Button(
            onClick = {
                userState = userState.copy(
                    name = "Kotlin-chan",
                    age = 25,
                    isLoggedIn = true
                )
            }
        ) {
            Text("Update")
        }

        Button(
            onClick = { userState = UserState() }
        ) {
            Text("Reset")
        }
    }
}

// ---- Derived state ----
@Composable
fun DerivedStateExample() {
    var count by remember { mutableStateOf(0) }
    val isEven = count % 2 == 0
    val parityText = if (isEven) "Even" else "Odd"

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text(text = "Count: $count ($parityText)")
        Text(
            text = "Is even: $isEven",
            color = if (isEven) Color.Green else Color.Red
        )
        Button(onClick = { count++ }) {
            Text("Increment")
        }
    }
}

// ---- State with rememberSaveable ----
@Composable
fun SaveableStateExample() {
    var text by rememberSaveable { mutableStateOf("") }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text(text = "Enter some text (survives configuration changes)")
        OutlinedTextField(
            value = text,
            onValueChange = { text = it },
            label = { Text("Text") }
        )
        Text(text = "You entered: $text")
    }
}

// ---- State hoisting ----
@Composable
fun StatelessCounter(
    count: Int,
    onIncrement: () -> Unit,
    onDecrement: () -> Unit
) {
    Column(
        modifier = Modifier.padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = "Count: $count",
            fontSize = 24.sp
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = onDecrement) {
                Text("-")
            }
            Button(onClick = onIncrement) {
                Text("+")
            }
        }
    }
}

@Composable
fun StatefulCounter() {
    var count by remember { mutableStateOf(0) }
    StatelessCounter(
        count = count,
        onIncrement = { count++ },
        onDecrement = { count-- }
    )
}

