data class TodoItem(val id: Int, val text: String, val isCompleted: Boolean = false)

@Composable
fun TodoList() {
    var items by remember { mutableStateListOf<TodoItem>() }
    var newText by remember { mutableStateOf("") }
    val completedCount = items.count { it.isCompleted }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
    ) {
        Text(
            text = "Todo List",
            fontSize = 24.sp,
            fontWeight = FontWeight.Bold
        )

        Spacer(modifier = Modifier.height(8.dp))

        Text(
            text = "Completed: $completedCount / ${items.size}",
            fontSize = 16.sp
        )

        Spacer(modifier = Modifier.height(16.dp))

        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            OutlinedTextField(
                value = newText,
                onValueChange = { newText = it },
                label = { Text("New todo") },
                modifier = Modifier.weight(1f)
            )
            Button(
                onClick = {
                    if (newText.isNotBlank()) {
                        items.add(TodoItem(items.size + 1, newText))
                        newText = ""
                    }
                }
            ) {
                Text("Add")
            }
        }

        Spacer(modifier = Modifier.height(16.dp))

        if (items.isEmpty()) {
            Text(
                text = "No todos yet. Add one above!",
                color = Color.Gray
            )
        } else {
            items.forEachIndexed { index, item ->
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 4.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Checkbox(
                        checked = item.isCompleted,
                        onCheckedChange = {
                            items[index] = item.copy(isCompleted = it)
                        }
                    )
                    Text(
                        text = item.text,
                        fontSize = 16.sp,
                        modifier = Modifier.padding(start = 8.dp)
                    )
                }
            }
        }
    }
}

